/**
 * Static survey dataset access.
 *
 * The microsite ships fully static. All survey numbers come from the committed
 * JSON generated by scripts/generate-state-of-startups-data.mjs — no live
 * Supabase at build or runtime. Every chart, stat, cross-tab, channel-mix, and
 * cohort toggle resolves to one pre-aggregated "distribution" looked up by a
 * canonical (year, column, aggregation, filters) key.
 */

import datasetJson from '../../../data/surveys/state-of-startups-data.json'
import type { SurveyYear } from '../components/year-context'

export type Aggregation = 'single' | 'multi' | 'boolean'

/** A filter value is an exact match (string) or an IN-list (array of strings). */
export type FilterValue = string | readonly string[]
export type SurveyFilters = Record<string, FilterValue>

export interface DistributionRow {
  label: string
  count: number
}

export interface Distribution {
  rows: DistributionRow[]
  respondentCount: number
}

/** One bar in a chart: label + rounded percentage + the unrounded value. */
export interface ChartDataItem {
  label: string
  value: number
  rawValue: number
}

interface SurveyDataset {
  meta: { generatedFrom: string; years: Record<string, number>; slices: number }
  distributions: Record<string, Distribution>
}

const dataset = datasetJson as SurveyDataset
const DISTRIBUTIONS = dataset.distributions

export const surveyMeta = dataset.meta

/**
 * Canonical cache key. MUST stay byte-identical to surveyKey() in
 * scripts/generate-state-of-startups-data.mjs, or runtime lookups miss the
 * generated data.
 */
function filterToken(filters?: SurveyFilters): string {
  if (!filters) return ''
  const keys = Object.keys(filters).sort()
  if (keys.length === 0) return ''
  return JSON.stringify(keys.map((k) => [k, filters[k]]))
}

export function surveyKey(
  year: SurveyYear,
  column: string,
  aggregation: Aggregation,
  filters?: SurveyFilters
): string {
  return `${year}|${column}|${aggregation}|${filterToken(filters)}`
}

/** Merges a base filter set with an extra cohort filter (the extra wins).
 *  Returns undefined when the result is empty so keys match the no-filter
 *  distributions. */
export function mergeFilters(
  base?: SurveyFilters,
  extra?: SurveyFilters
): SurveyFilters | undefined {
  const merged = { ...(base ?? {}), ...(extra ?? {}) }
  return Object.keys(merged).length > 0 ? merged : undefined
}

/** Returns the pre-aggregated distribution, or undefined when the column did
 *  not exist that year (e.g. a new-in-2026 question viewed at 2025). */
export function getDistribution(
  year: SurveyYear,
  column: string,
  aggregation: Aggregation,
  filters?: SurveyFilters
): Distribution | undefined {
  return DISTRIBUTIONS[surveyKey(year, column, aggregation, filters)]
}

/** Sums the matching target rows over the respondent denominator. Returns null
 *  when there is no data for the year or the target option is absent. */
export function distributionPercent(
  dist: Distribution | undefined,
  target: string | readonly string[]
): number | null {
  if (!dist || dist.respondentCount <= 0) return null
  const targets = Array.isArray(target) ? target : [target]
  let count = 0
  let matched = 0
  for (const row of dist.rows) {
    if (targets.includes(row.label)) {
      count += row.count
      matched += 1
    }
  }
  if (matched === 0) return null
  return Math.round((count / dist.respondentCount) * 100)
}

/** Maps a distribution to chart bars (respondent-count denominator), already
 *  sorted desc by the generator. Optionally caps the number of bars. */
export function distributionToBars(
  dist: Distribution | undefined,
  maxBars?: number
): ChartDataItem[] {
  if (!dist || dist.respondentCount <= 0) return []
  const bars = dist.rows.map((row) => {
    const raw = (row.count / dist.respondentCount) * 100
    return { label: row.label, value: Math.round(raw), rawValue: raw }
  })
  return maxBars ? bars.slice(0, maxBars) : bars
}
